// ============================================================================
// SCORE TASK HYGIENE
// Runs once over every OPEN task passed in from the filter. Each task is checked
// against the completeness rules, and ONE audit row is emitted per FAILING task
// (a task with at least one violation). Fully-fielded tasks are skipped here, so
// the Google Sheets append only ever logs a task that needs attention.
//
// Read-only: this node never writes anything back to Asana.
// ============================================================================

const cfg = $('Set Audit Config').first().json;
const checkSection = cfg.checkSection === true || cfg.checkSection === 'true';
const checkDescription = cfg.checkDescription === true || cfg.checkDescription === 'true';
const auditDate = $now.toFormat('yyyy-LL-dd');

const rows = [];

for (const item of $input.all()) {
  const t = item.json || {};
  const reasons = [];

  // Assignee: Asana returns assignee:null when nobody is assigned.
  const assigneeName = (t.assignee && (t.assignee.name || t.assignee.gid)) ? (t.assignee.name || 'assigned') : '';
  if (!t.assignee) reasons.push('no_assignee');

  // Due date: due_on is a yyyy-mm-dd string, or null when no date is set.
  if (!t.due_on) reasons.push('no_due_date');

  // Section: the task's first project membership carries the section name.
  let sectionName = '';
  if (Array.isArray(t.memberships) && t.memberships.length && t.memberships[0] && t.memberships[0].section) {
    sectionName = t.memberships[0].section.name || '';
  }
  if (checkSection && !sectionName) reasons.push('no_section');

  // Description: Asana calls the description "notes".
  const notes = (t.notes || '').toString().trim();
  if (checkDescription && !notes) reasons.push('empty_description');

  if (reasons.length === 0) continue; // only flagged tasks reach the audit log

  rows.push({
    json: {
      audit_date: auditDate,
      task_gid: t.gid || '',
      task_name: t.name || '(unnamed task)',
      assignee: assigneeName,
      section: sectionName,
      due_on: t.due_on || '',
      reason_codes: reasons.join(','),
      permalink_url: t.permalink_url || '',
    },
  });
}

return rows;

// ============================================================================
// BUILD SLACK SCORECARD
// Reads the full task list straight from the Asana fetch (so the scorecard posts
// every week even when nothing is flagged, or when there are zero open tasks) and
// computes the run-level numbers deterministically:
//   - open task count
//   - how many tasks fail each enabled check
//   - overall percent of open tasks that are fully fielded
//   - the top offenders (most failing checks first)
// Emits ONE scorecard item. Every number here is computed in plain code; no model
// is involved in the scoring.
// ============================================================================

const cfg = $('Set Audit Config').first().json;
const checkSection = cfg.checkSection === true || cfg.checkSection === 'true';
const checkDescription = cfg.checkDescription === true || cfg.checkDescription === 'true';
const sheetUrl = (cfg.auditSheetUrl || '').toString().trim();
const auditDate = $now.toFormat('yyyy-LL-dd');

const resp = $('Fetch Asana Tasks').first().json || {};
const all = Array.isArray(resp.data) ? resp.data : [];
const open = all.filter((t) => t && t.completed !== true);

let noAssignee = 0, noDue = 0, noSection = 0, emptyDesc = 0;
const offenders = [];

for (const t of open) {
  const reasons = [];
  if (!t.assignee) { noAssignee++; reasons.push('no_assignee'); }
  if (!t.due_on) { noDue++; reasons.push('no_due_date'); }

  let sectionName = '';
  if (Array.isArray(t.memberships) && t.memberships.length && t.memberships[0] && t.memberships[0].section) {
    sectionName = t.memberships[0].section.name || '';
  }
  if (checkSection && !sectionName) { noSection++; reasons.push('no_section'); }

  const notes = (t.notes || '').toString().trim();
  if (checkDescription && !notes) { emptyDesc++; reasons.push('empty_description'); }

  if (reasons.length) offenders.push({ name: t.name || '(unnamed task)', count: reasons.length, reasons });
}

const openCount = open.length;
const flaggedCount = offenders.length;
const fullyFielded = openCount - flaggedCount;
const pct = openCount ? Math.round((fullyFielded / openCount) * 100) : 100;

offenders.sort((a, b) => b.count - a.count);
const top = offenders.slice(0, 5);

const NL = String.fromCharCode(10);
const lines = [];
lines.push(':bar_chart: *Asana task hygiene scorecard*  (' + auditDate + ')');
lines.push(fullyFielded + ' of ' + openCount + ' open task' + (openCount === 1 ? '' : 's') + ' fully fielded (' + pct + '%). ' + flaggedCount + ' flagged.');
lines.push('');
lines.push(':bust_in_silhouette: Missing assignee: ' + noAssignee);
lines.push(':calendar: Missing due date: ' + noDue);
if (checkSection) lines.push(':card_index_dividers: Missing section: ' + noSection);
if (checkDescription) lines.push(':memo: Empty description: ' + emptyDesc);
if (top.length) {
  lines.push('');
  lines.push('*Top offenders*');
  for (const o of top) lines.push('- ' + o.name + '  (' + o.reasons.join(', ') + ')');
}
if (sheetUrl) {
  lines.push('');
  lines.push('Full audit log: ' + sheetUrl);
}
const scorecardText = lines.join(NL);

return [{
  json: {
    auditDate,
    openCount,
    flaggedCount,
    fullyFielded,
    pctFullyFielded: pct,
    counts: { noAssignee, noDue, noSection, emptyDesc },
    topOffenders: top,
    scorecardText,
  },
}];
